UPDATE servicios SET tarifario = '{"base":{"label":"Sistema Instaclip para tomar la foto (Aro de luz portátil + iPhone + Nuestra App IA)","descripcion":"El operador toma la foto, la IA la procesa en aprox 30 segundos y se comparte por QR al instante.  Se puede poner sobre un trípode con un foco de iluminación.  Filtro IA - Action Figure:  La foto se la persona se transforma en una Figura Coleccionable y se inserta en un diseño de caja con íconos de la marca y logo. Se podrán tener 3 variaciones de caja con distintos accesorios.  Referente: https://drive.google.com/file/d/1DI0_G4q8233jjvhmb4bGOE3BWvtmCYFQ/view?usp=sharing","unitario":950000},"adicionales":[{"label":"Print Station -  4 horas","descripcion":"Impresión de fotos instantáneas con logo. Tamaño 10x15 cms","unitario":200000},{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000}],"packs":[{"label":"Foto Fotográfico touch de 43 pulgadas con App IA","descripcion":"El operador toma la foto, la IA la procesa en aprox 30 segundos y se comparte por QR al instante.  Filtro IA - Action Figure:  La foto se la persona se transforma en una Figura Coleccionable y se inserta en un diseño de caja con íconos de la marca y logo. Se podrán tener 3 variaciones de caja con distintos accesorios.  Referente: https://drive.google.com/file/d/1tVxK2eUmtHn7J-iPExuDQfdrj0hOaCWl/view?usp=sharing","unitario":1250000}]}' WHERE nombre = 'Action Figure' AND (tarifario IS NULL OR tarifario = '');
