UPDATE servicios SET tarifario = '{"base":{"label":"Sistema Arte con IA - 4 horas","descripcion":"Incluye Tótem touch de 43 pulgadas, softwares IA y scripts. Incluye Prompt Engineering para que las imagenes creadas tengan relación con el evento. Mosaico que forma el logo de la marca con las imagenes creadas por los asistentes.  El mosaico se entrega 30 minutos después de finalizada la actividad. Se entrega en formato JPG y se envía al correo por WeTransfer.","unitario":1150000},"adicionales":[{"label":"Tótem Touch, día completo (10 hrs) EXTRA","descripcion":"","unitario":450000},{"label":"Estudio Chroma","descripcion":"Primero la persona pasa por el tótem para generar su fondo con IA. Luego, la persona se toma una foto frente a nuestra cámara reflex a un costado del tótem y se genera un montaje de la persona sobre el fondo creado con IA).","unitario":350000},{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000},{"label":"Print Station - por hora","descripcion":"Impresión de fotos instantáneas con logo. Tamaño 10x15 cms","unitario":65000}],"packs":[]}' WHERE nombre = 'Arte con IA' AND (tarifario IS NULL OR tarifario = '');
UPDATE servicios SET tarifario = '{"base":{"label":"Sistema Instant Art con IA - 4 horas","descripcion":"Incluye Tótem touch de 55 pulgadas, softwares IA y scripts. Incluye cámara para capturar a la persona. Incluye Prompt Engineering para que las imagenes creadas tengan relación con el evento. Se genera una imagen en tiempo real en la pantalla la cual cambia según el comportamiento de la persona.  * Se puede reemplazar el tótem por conexión directa a la pantalla LED que tengan en el Stand/Evento. En este caso el visualista debe entregarnos un cable HDMI que conecte directo nuestro computador a su mesa de trabajo","unitario":1950000},"adicionales":[{"label":"Instant Art, día completo (10 hrs) EXTRA","descripcion":"","unitario":950000},{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000}],"packs":[]}' WHERE nombre = 'GenAI Wall' AND (tarifario IS NULL OR tarifario = '');
UPDATE servicios SET tarifario = '{"base":{"label":"Sistema Instant Art con IA - 4 horas","descripcion":"Incluye Tótem touch de 55 pulgadas, softwares IA y scripts. Incluye cámara para capturar a la persona. Incluye Prompt Engineering para que las imagenes creadas tengan relación con el evento. Utilizando Generative AI Image, crearemos la imagen con la que inicia el video y una imagen con la que termina. Utilizando Generative AI Video y una descripción detallada de la escena, le pediremos a la IA que interprete el movimiento de inicio a fin.  Duración: 10 segundos Formato: mp4 Tamaño: 9:16   El proceso en total toma aproximadamente de 3 a 5 minutos. Por lo que les llega posterior a sus correos.  * Se puede reemplazar el tótem por conexión directa a la pantalla LED que tengan en el Stand/Evento. En este caso el visualista debe entregarnos un cable HDMI que conecte directo nuestro computador a su mesa de trabajo","unitario":1950000},"adicionales":[{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000}],"packs":[{"label":"2 a 3 días completos (tope 10 horas por dia). Valor diario","descripcion":"","unitario":1800000},{"label":"4 o más días completos (tope 10 horas por dia). Valor diario","descripcion":"","unitario":1650000}]}' WHERE nombre = 'AI Video' AND (tarifario IS NULL OR tarifario = '');
