UPDATE servicios SET tarifario = '{"base":{"label":"Avatar hablante","descripcion":"Incluye configurar la cara de un humano (gerente, colaborador, etc). Incluye crear un avatar usando IA que represente a la marca.  Incluye hasta 5 minutos hablados. Incluye casting de voces con IA (te enviaremos 5 propuestas de voz de hombre y mujer para que elijas la que más representa a tu marca). Se puede usar tambien audio enviado por el cliente  * No se pueden usar rostros famosos ya que el programa los rechaza por riesgos de Deepfake.","unitario":280000},"adicionales":[],"packs":[{"label":"Pack 5 minutos adicionales","descripcion":"(variante)","unitario":120000},{"label":"Sistema para que el Avatar salude a los asistentes al ingresar","descripcion":"Esto considera un operador con un botón a distancia. Para lograr el efecto, creamos 5 loops de videos con distintos saludos + 1 video en \"reposo\".  Cuando una persona pase frente al avatar, nuestro operador activará el saludo. Los asistentes pensarán que el avatar los vio pasar y los saludó.  En caso de conectarnos a un proveedor de pantallas LED, se debe coordinar para poder switchear al avatar con teclado inalambrico.","unitario":400000},{"label":"Tótem 55 pulgadas dual pantalla (opcional)","descripcion":"(variante)","unitario":300000}]}' WHERE nombre = 'Avatar Pre Grabado' AND (tarifario IS NULL OR tarifario = '');
