UPDATE servicios SET tarifario = '{"base":{"label":"Octágono futbol con sensores","descripcion":"","unitario":950000},"adicionales":[{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000},{"label":"Branding completo.","descripcion":"En caso de no brandear, el color de la estructura es negro","unitario":550000},{"label":"Totem touch con Ranking","descripcion":"Se desarrollara un sistema tipo ranking donde la persona antes de ingresar al octagono se registra (al finalizar el evento se envian los datos recopilados al cliente). Cuando la persona termina de jugar, nuestro operador ingresa el puntaje obtenido. De esta manera obtendremos un ranking que se muestra en pantalla con los mejores puntajes.","unitario":550000}],"packs":[]}' WHERE nombre = 'Octagono' AND (tarifario IS NULL OR tarifario = '');
UPDATE servicios SET tarifario = '{"base":{"label":"Corresponde 6 botones/sensores que se pegan a algún muro o estructura del stand con doble contacto (no la incluye, la debe proveer el cliente).","descripcion":"- Estos sensores se conectan a una APP donde se puede ver el puntaje final. - Estos sensores permiten crear juegos donde compitan 2 personas ya que se prenden de distintos colores. - Existen multiples tipos de juegos y dinámicas  Además, incluye una pantalla touch con atril (o empotrada en el stand), donde el jugador se inscribe previamente para mostrar los mejores puntajes de la jornada.  Referente: https://drive.google.com/file/d/1eyJtnYYR3ASQH2-nrFWkDlNNvvr8JEsn/view?usp=sharing","unitario":850000},"adicionales":[{"label":"Promotor(a) / con conocimiento operativo del servicio","descripcion":"","unitario":100000},{"label":"Animador","descripcion":"","unitario":200000},{"label":"Branding completo.","descripcion":"En caso de no brandear, el color de la estructura es negro","unitario":350000}],"packs":[{"label":"Lo mismo que el punto anterior pero además incluye una estructura de fierro autosoportante donde se instalan los botones/sensores","descripcion":"Referente: https://drive.google.com/file/d/1In6QHbs3v3LooMitStrmzXeSpUVZC5a7/view?usp=sharing","unitario":1250000},{"label":"Corresponde a un muro de 2x2 con branding del cliente.","descripcion":"En este muro ya vienen empotrados los 6 botones/sensores y la TV touch.  A diferencia de la version LIGHT que solo tiene un ranking, en este se puede personalizar una interfaz más completa que tiene: - Menu de inicio - Cuenta regresiva - Puntaje en pantalla el tiempo real - Puntaje final  Referente: https://drive.google.com/file/d/1IItGW06-F4uVfN476eG3TPVlOH9cu9-z/view?usp=sharing","unitario":1650000}]}' WHERE nombre = 'MuroReact' AND (tarifario IS NULL OR tarifario = '');
